import '@testing-library/jest-dom';
// This file was generated by an AI agent. Do not edit directly.
import * as React from 'react';
import { render, screen, fireEvent } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { FileUpload } from './FileUpload';

const createMockFile = (name: string, type: string) => new File(['file'], name, { type });

let lastCreatedImage: {
  onload: (() => void) | null;
  onerror: (() => void) | null;
} | null = null;

class TestImage {
  onload: (() => void) | null = null;
  onerror: (() => void) | null = null;
  decode?: () => Promise<void>;
  private _src = '';

  constructor() {
    // eslint-disable-next-line @typescript-eslint/no-this-alias
    lastCreatedImage = this;
  }

  set src(value: string) {
    this._src = value;
  }

  get src(): string {
    return this._src;
  }
}

const triggerImageLoad = () => {
  lastCreatedImage?.onload?.();
};

const triggerImageError = () => {
  lastCreatedImage?.onerror?.();
};

describe('FileUpload', () => {
  const originalImage = global.Image;

  beforeAll(() => {
    Object.defineProperty(global.URL, 'createObjectURL', {
      value: jest.fn(() => 'blob:mock-preview'),
      writable: true
    });
    Object.defineProperty(global.URL, 'revokeObjectURL', {
      value: jest.fn(),
      writable: true
    });
  });

  beforeEach(() => {
    lastCreatedImage = null;
    // @ts-expect-error - override global constructor for tests
    global.Image = TestImage;
    jest.resetAllMocks();
  });

  afterAll(() => {
    global.Image = originalImage;
  });

  it('renders the dropzone button with the provided label', () => {
    render(<FileUpload label="Profile photo" />);
    expect(screen.getByRole('button', { name: 'Profile photo' })).toBeInTheDocument();
  });

  it('omits the hint slot when error text is provided', () => {
    render(<FileUpload label="Profile photo" hint="Helpful hint" error="Upload failed." />);
    expect(document.querySelector('[data-slot="hint"]')).toBeNull();
  });

  it('rejects files that do not satisfy the accept filter', () => {
    const onFileError = jest.fn();
    render(<FileUpload label="Profile photo" onFileError={onFileError} />);
    const dropzone = screen.getByRole('button', { name: 'Profile photo' });
    const invalidFile = createMockFile('notes.txt', 'text/plain');
    fireEvent.drop(dropzone, {
      dataTransfer: { files: [invalidFile] }
    });
    expect(onFileError).toHaveBeenCalledWith(
      expect.objectContaining({ message: 'Upload failed', file: invalidFile })
    );
  });

  it('clears drag-over state and announces cancel on drag leave', () => {
    const { container } = render(<FileUpload label="Profile photo" />);
    const dropzone = screen.getByRole('button', { name: 'Profile photo' });
    const root = container.firstElementChild as HTMLElement;

    // Enter drag to set the state
    fireEvent.dragEnter(dropzone, { dataTransfer: { types: ['Files'] } });
    expect(root.getAttribute('data-drag-over')).toBe('true');

    // Leave drag to clear the state and announce cancel
    fireEvent.dragLeave(dropzone);
    expect(root.getAttribute('data-drag-over')).toBeNull();

    const live = screen.getByRole('status');
    expect(live.textContent?.trim()).toBe('Drag canceled');
  });

  it('sets dropEffect to copy and announces "Drop now" on drag over', () => {
    const { container } = render(<FileUpload label="Profile photo" />);
    const dropzone = screen.getByRole('button', { name: 'Profile photo' });
    const root = container.firstElementChild as HTMLElement;

    const dataTransfer = { dropEffect: 'none', types: ['Files'] };
    fireEvent.dragOver(dropzone, { dataTransfer });

    expect(root.getAttribute('data-drag-over')).toBe('true');
    expect(dataTransfer.dropEffect).toBe('copy');

    const live = screen.getByRole('status');
    expect(live.textContent?.trim()).toBe('Drop now');
  });

  it('enters the uploading state after an image is selected', () => {
    const { container } = render(<FileUpload label="Profile photo" />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const imageFile = createMockFile('photo.png', 'image/png');
    fireEvent.change(fileInput, { target: { files: [imageFile] } });
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-uploading')).toBe('true');
  });

  it('cancels the upload and returns to the empty state', () => {
    const onFileCanceled = jest.fn();
    const { container } = render(
      <FileUpload label="Profile photo" onFileCanceled={onFileCanceled} />
    );
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const imageFile = createMockFile('photo.png', 'image/png');
    fireEvent.change(fileInput, { target: { files: [imageFile] } });
    const cancelLink = screen.getByRole('link', { name: 'Cancel upload' });
    fireEvent.click(cancelLink);
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-uploading')).toBeNull();
  });

  it('marks the upload as accepted after preview decoding succeeds', () => {
    const { container } = render(<FileUpload label="Profile photo" />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const imageFile = createMockFile('photo.png', 'image/png');
    fireEvent.change(fileInput, { target: { files: [imageFile] } });
    triggerImageLoad();
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-accepted')).toBe('true');
  });

  it('emits onFileChanging when replacing an accepted file', () => {
    const onFileChanging = jest.fn();
    const { container } = render(
      <FileUpload label="Profile photo" onFileChanging={onFileChanging} />
    );
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const firstFile = createMockFile('photo.png', 'image/png');
    fireEvent.change(fileInput, { target: { files: [firstFile] } });
    triggerImageLoad();
    const secondFile = createMockFile('photo-2.png', 'image/png');
    fireEvent.change(fileInput, { target: { files: [secondFile] } });
    expect(onFileChanging).toHaveBeenCalledWith(
      expect.objectContaining({ message: 'Changing file', file: secondFile })
    );
  });

  it('removes an accepted file via the secondary action', () => {
    const { container } = render(
      <FileUpload label="Upload document" accept="application/pdf" fileNoun="document" />
    );
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const pdfFile = createMockFile('policy.pdf', 'application/pdf');
    fireEvent.change(fileInput, { target: { files: [pdfFile] } });
    const removeLink = screen.getByRole('link', { name: 'Remove document' });
    fireEvent.click(removeLink);
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-accepted')).toBeNull();
  });

  it('retains the uploading state when preview fails and resetOnFail is false', () => {
    const { container } = render(<FileUpload label="Profile photo" />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const imageFile = createMockFile('photo.png', 'image/png');
    fireEvent.change(fileInput, { target: { files: [imageFile] } });
    triggerImageError();
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-uploading')).toBe('true');
  });

  it('resets to the empty state when preview fails and resetOnFail is true', () => {
    const { container } = render(<FileUpload label="Profile photo" resetOnFail />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const imageFile = createMockFile('photo.png', 'image/png');
    fireEvent.change(fileInput, { target: { files: [imageFile] } });
    triggerImageError();
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-uploading')).toBeNull();
  });

  it('retains the focus-visible ring classes on the dropzone', async () => {
    const user = userEvent.setup();
    render(<FileUpload ariaLabel="Upload file" />);
    await user.tab();
    const dropzone = screen.getByRole('button', { name: 'Upload file' });
    expect(dropzone.className).toContain('focus-visible:ring-2');
  });

  it('opens the file dialog when pressing Enter/Space on the dropzone', () => {
    const { container } = render(<FileUpload ariaLabel="Upload file" />);
    const dropzone = screen.getByRole('button', { name: 'Upload file' });
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;

    const clickSpy = jest.spyOn(fileInput, 'click').mockImplementation(() => {});

    // Press Enter
    fireEvent.keyDown(dropzone, { key: 'Enter' });
    // Press Space
    fireEvent.keyDown(dropzone, { key: ' ' });

    expect(clickSpy).toHaveBeenCalledTimes(2);
    clickSpy.mockRestore();
  });

  it('opens the file dialog when clicking the primary action button', () => {
    const { container } = render(<FileUpload ariaLabel="Upload file" />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const clickSpy = jest.spyOn(fileInput, 'click').mockImplementation(() => {});

    const primaryButton = document.querySelector(
      '[data-slot="primaryAction"] button'
    ) as HTMLButtonElement;
    expect(primaryButton).toBeInTheDocument();

    fireEvent.click(primaryButton);
    expect(clickSpy).toHaveBeenCalledTimes(1);
    clickSpy.mockRestore();
  });

  it('does not open the file dialog when uploading and the primary action is clicked', () => {
    const { container } = render(<FileUpload label="Profile photo" />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const clickSpy = jest.spyOn(fileInput, 'click').mockImplementation(() => {});

    // Enter uploading state
    const imageFile = new File(['file'], 'photo.png', { type: 'image/png' });
    fireEvent.change(fileInput, { target: { files: [imageFile] } });

    const primaryButton = document.querySelector(
      '[data-slot="primaryAction"] button'
    ) as HTMLButtonElement;
    expect(primaryButton).toBeDisabled(); // disabled while uploading
    fireEvent.click(primaryButton);
    expect(clickSpy).toHaveBeenCalledTimes(0);
    clickSpy.mockRestore();
  });

  it('falls back to the placeholder image when the preview image errors after acceptance', () => {
    const { container } = render(<FileUpload label="Profile photo" />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const imageFile = new File(['file'], 'photo.png', { type: 'image/png' });

    // Select image and complete preview decode success
    fireEvent.change(fileInput, { target: { files: [imageFile] } });
    triggerImageLoad();

    // Image is accepted; now trigger onError on the <img>
    const img = container.querySelector('img') as HTMLImageElement;
    fireEvent.error(img);

    // After error, component should show placeholder src (string path)
    expect(img.getAttribute('src')).toBe('./fileThumbnail.png');
  });

  it('marks the root as invalid when an error is present', () => {
    const { container } = render(<FileUpload label="Profile photo" error="Upload failed." />);
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-invalid')).toBe('true');
  });

  it('retains the group-hover class on the primary action wrapper', () => {
    render(<FileUpload label="Profile photo" />);
    const wrapper = document.querySelector('[data-slot="primaryAction"]') as HTMLElement;
    expect(wrapper.className).toContain(
      'group-hover:[&_*]:bg-comp-button-primary-color-background-hover'
    );
  });

  it('renders default photo image properties when none are provided', () => {
    render(<FileUpload label="Profile photo" />);
    expect(screen.getByText('Supports: PNG and JPG')).toBeInTheDocument();
  });

  it('renders poster defaults when imageFormat is poster', () => {
    render(<FileUpload label="Poster" imageFormat="poster" />);
    expect(screen.getByText('Max dimensions: 840px x 1120px')).toBeInTheDocument();
  });

  it('accepts an initialValue on mount and marks as accepted', () => {
    const { container } = render(
      <FileUpload label="Profile photo" initialValue="https://example.com/avatar.jpg" />
    );
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-accepted')).toBe('true');
  });

  it('clears preview and returns to empty when initialValue is removed (no file present)', () => {
    const { container, rerender } = render(
      <FileUpload label="Profile photo" initialValue="https://example.com/avatar.jpg" />
    );
    const root = container.firstElementChild as HTMLElement;
    expect(root.getAttribute('data-accepted')).toBe('true');

    // Remove the initialValue; since no file is present, the effect should reset to empty
    rerender(<FileUpload label="Profile photo" />);
    const updatedRoot = container.firstElementChild as HTMLElement;
    expect(updatedRoot.getAttribute('data-accepted')).toBeNull();

    // Thumbnail should revert to placeholder
    const img = container.querySelector('img') as HTMLImageElement;
    expect(img.getAttribute('src')).toBe('./fileThumbnail.png');
  });

  it('does not override an accepted file when initialValue changes', () => {
    const { container, rerender } = render(<FileUpload label="Profile photo" />);
    const fileInput = container.querySelector('input[type="file"]') as HTMLInputElement;
    const imageFile = new File(['file'], 'photo.png', { type: 'image/png' });
    fireEvent.change(fileInput, { target: { files: [imageFile] } });
    triggerImageLoad();

    // Now change initialValue; guard should prevent overwrite while a file is present
    rerender(<FileUpload label="Profile photo" initialValue="https://example.com/new.jpg" />);
    const img = container.querySelector('img') as HTMLImageElement;
    expect(img.getAttribute('src')).not.toBe('https://example.com/new.jpg');
  });
});
